ALTER TABLE "WaterTest" ADD COLUMN "poolId" TEXT REFERENCES "PoolProfile"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "PhotoDiagnostic" ADD COLUMN "poolId" TEXT REFERENCES "PoolProfile"("id") ON DELETE SET NULL ON UPDATE CASCADE;
CREATE TABLE "RecommendationExecution" ("id" TEXT NOT NULL PRIMARY KEY,"userId" TEXT NOT NULL,"poolId" TEXT NOT NULL,"actionPlanId" TEXT NOT NULL,"actionIndex" INTEGER NOT NULL,"actionLabel" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'planned',"productName" TEXT,"plannedDosage" TEXT,"actualDosage" REAL,"actualUnit" TEXT,"note" TEXT,"executedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE,FOREIGN KEY("poolId") REFERENCES "PoolProfile"("id") ON DELETE CASCADE ON UPDATE CASCADE,FOREIGN KEY("actionPlanId") REFERENCES "ActionPlan"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "RecommendationOutcome" ("id" TEXT NOT NULL PRIMARY KEY,"userId" TEXT NOT NULL,"poolId" TEXT NOT NULL,"actionPlanId" TEXT NOT NULL,"baselineWaterTestId" TEXT NOT NULL,"followupWaterTestId" TEXT,"status" TEXT NOT NULL DEFAULT 'awaiting_retest',"clearWaterIndexBefore" INTEGER,"clearWaterIndexAfter" INTEGER,"userRating" INTEGER,"userFeedback" TEXT,"evaluatedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE,FOREIGN KEY("poolId") REFERENCES "PoolProfile"("id") ON DELETE CASCADE,FOREIGN KEY("actionPlanId") REFERENCES "ActionPlan"("id") ON DELETE CASCADE,FOREIGN KEY("baselineWaterTestId") REFERENCES "WaterTest"("id") ON DELETE CASCADE,FOREIGN KEY("followupWaterTestId") REFERENCES "WaterTest"("id") ON DELETE SET NULL);
CREATE TABLE "BrainFeedback" ("id" TEXT NOT NULL PRIMARY KEY,"userId" TEXT NOT NULL,"poolId" TEXT,"contextType" TEXT NOT NULL,"contextId" TEXT,"rating" INTEGER,"helpful" BOOLEAN,"message" TEXT,"status" TEXT NOT NULL DEFAULT 'new',"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE,FOREIGN KEY("poolId") REFERENCES "PoolProfile"("id") ON DELETE SET NULL);
CREATE TABLE "KnowledgeArticle" ("id" TEXT NOT NULL PRIMARY KEY,"slug" TEXT NOT NULL,"category" TEXT NOT NULL,"audience" TEXT NOT NULL DEFAULT 'all',"riskLevel" TEXT NOT NULL DEFAULT 'standard',"status" TEXT NOT NULL DEFAULT 'draft',"currentVersion" INTEGER NOT NULL DEFAULT 1,"tags" TEXT,"relatedSlugs" TEXT,"publishedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL);
CREATE TABLE "KnowledgeRevision" ("id" TEXT NOT NULL PRIMARY KEY,"articleId" TEXT NOT NULL,"version" INTEGER NOT NULL,"locale" TEXT NOT NULL DEFAULT 'fr',"title" TEXT NOT NULL,"summary" TEXT,"content" TEXT NOT NULL,"sources" TEXT,"changeNote" TEXT,"createdBy" TEXT,"reviewedBy" TEXT,"reviewedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY("articleId") REFERENCES "KnowledgeArticle"("id") ON DELETE CASCADE);
CREATE TABLE "BrainEventOutbox" ("id" TEXT NOT NULL PRIMARY KEY,"idempotencyKey" TEXT NOT NULL,"type" TEXT NOT NULL,"aggregateType" TEXT NOT NULL,"aggregateId" TEXT NOT NULL,"payload" TEXT,"status" TEXT NOT NULL DEFAULT 'pending',"attempts" INTEGER NOT NULL DEFAULT 0,"nextAttemptAt" DATETIME,"lockedAt" DATETIME,"processedAt" DATETIME,"lastError" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "RecommendationExecution_actionPlanId_actionIndex_key" ON "RecommendationExecution"("actionPlanId","actionIndex");
CREATE UNIQUE INDEX "RecommendationOutcome_actionPlanId_key" ON "RecommendationOutcome"("actionPlanId");
CREATE UNIQUE INDEX "RecommendationOutcome_followupWaterTestId_key" ON "RecommendationOutcome"("followupWaterTestId");
CREATE UNIQUE INDEX "KnowledgeArticle_slug_key" ON "KnowledgeArticle"("slug");
CREATE UNIQUE INDEX "KnowledgeRevision_articleId_version_locale_key" ON "KnowledgeRevision"("articleId","version","locale");
CREATE UNIQUE INDEX "BrainEventOutbox_idempotencyKey_key" ON "BrainEventOutbox"("idempotencyKey");
CREATE INDEX "WaterTest_poolId_createdAt_idx" ON "WaterTest"("poolId","createdAt");CREATE INDEX "PhotoDiagnostic_poolId_idx" ON "PhotoDiagnostic"("poolId");CREATE INDEX "RecommendationOutcome_status_idx" ON "RecommendationOutcome"("status");CREATE INDEX "BrainEventOutbox_status_nextAttemptAt_idx" ON "BrainEventOutbox"("status","nextAttemptAt");
